 try
 {
     var metrics = mlContext.BinaryClassification.Evaluate(testPredictions, labelColumnName: "Label");
     Console.WriteLine($"Model metrics — AUC: {metrics.AreaUnderRocCurve:F4}, Accuracy: {metrics.Accuracy:F4}, F1: {metrics.F1Score:F4}");
 }
 catch (ArgumentOutOfRangeException)
 {
     Console.WriteLine("Dataset too small for full evaluation metrics. Add more labeled data for reliable metrics.");
 }

 // Save the model (retrained on all data) and register prediction engine pool
